<?php
namespace App\Filament\Resources; use App\Filament\Resources\AttendanceResource\Pages; use App\Modules\Attendance\Models\Attendance; use App\Modules\Attendance\Models\Enums\AttendanceStatus; use Filament\Forms; use Filament\Forms\Form; use Filament\Resources\Resource; use Filament\Tables; use Filament\Tables\Table;
class AttendanceResource extends Resource { protected static ?string $model=Attendance::class; protected static ?string $navigationIcon='heroicon-o-clock'; protected static ?string $navigationGroup='Nhân sự'; protected static ?string $modelLabel='Chấm công'; protected static ?string $pluralModelLabel='Chấm công'; public static function form(Form $form): Form { return $form->schema([Forms\Components\Select::make('user_id')->label('Nhân viên')->relationship('user','name')->searchable()->preload()->required(), Forms\Components\DatePicker::make('work_date')->label('Ngày làm')->required(), Forms\Components\DateTimePicker::make('check_in_at')->label('Check-in'), Forms\Components\DateTimePicker::make('check_out_at')->label('Check-out'), Forms\Components\Select::make('status')->label('Trạng thái')->options(self::enumOptions(AttendanceStatus::class))->required(), Forms\Components\TextInput::make('check_in_method')->label('Cách check-in'), Forms\Components\TextInput::make('check_out_method')->label('Cách check-out'), Forms\Components\TextInput::make('check_in_lat')->label('Lat in'), Forms\Components\TextInput::make('check_in_lng')->label('Lng in'), Forms\Components\TextInput::make('check_out_lat')->label('Lat out'), Forms\Components\TextInput::make('check_out_lng')->label('Lng out'), Forms\Components\Textarea::make('note')->label('Ghi chú')->columnSpanFull()])->columns(2); } public static function table(Table $table): Table { return $table->columns([Tables\Columns\TextColumn::make('user.name')->label('Nhân viên')->searchable(), Tables\Columns\TextColumn::make('work_date')->label('Ngày')->date('d/m/Y'), Tables\Columns\TextColumn::make('check_in_at')->label('Vào')->dateTime('H:i'), Tables\Columns\TextColumn::make('check_out_at')->label('Ra')->dateTime('H:i'), Tables\Columns\TextColumn::make('status')->label('Trạng thái')->formatStateUsing(fn($state)=>$state instanceof AttendanceStatus?$state->label():AttendanceStatus::tryFrom((int)$state)?->label())->badge()])->actions([Tables\Actions\EditAction::make(),Tables\Actions\DeleteAction::make()]); } public static function getPages(): array { return ['index'=>Pages\ListAttendances::route('/'),'create'=>Pages\CreateAttendance::route('/create'),'edit'=>Pages\EditAttendance::route('/{record}/edit')]; } private static function enumOptions(string $enum): array { return collect($enum::cases())->mapWithKeys(fn($case)=>[$case->value=>$case->label()])->all(); } }
